    a = math.isqrt(n) + 1
    while True:
        b2 = a**2 - n
        if is_perfect_square(b2):
            b = math.isqrt(b2)
            break
        a = a + 1

    p = a + b
    q = a - b
    print(isPrime(p))
    print(isPrime(q))

    phi_n = (p-1)*(q-1)

    d = inverse(e, phi_n)

    plaintext = pow(c, d, n)

    flag = long_to_bytes(plaintext).decode()

    print("The given flag is: " + flag)

